import{_ as e,c as l,o as a,ae as i}from"./chunks/framework.CMFi8ROq.js";const c=JSON.parse('{"title":"PLM","description":"","frontmatter":{},"headers":[],"relativePath":"interview/PLM.md","filePath":"interview/PLM.md","lastUpdated":1777978720000}'),n={name:"interview/PLM.md"};function r(o,t,s,d,u,m){return a(),l("div",null,t[0]||(t[0]=[i('<h1 id="plm" tabindex="-1">PLM <a class="header-anchor" href="#plm" aria-label="Permalink to &quot;PLM&quot;">​</a></h1><h2 id="核心概念" tabindex="-1">核心概念 <a class="header-anchor" href="#核心概念" aria-label="Permalink to &quot;核心概念&quot;">​</a></h2><h5 id="单一数据源" tabindex="-1">单一数据源 <a class="header-anchor" href="#单一数据源" aria-label="Permalink to &quot;单一数据源&quot;">​</a></h5><ul><li>定义：这是 PLM 的灵魂。指企业内所有与产品相关的信息（图纸、BOM、规格书、工艺文件）都存储在一个中央平台上，所有人都访问这“唯一”的、最新的数据。</li><li>价值：彻底消除“信息孤岛”，避免研发用 V2.0 图纸，车间却在按 V1.5 图纸生产的灾难。</li></ul><h5 id="bom-bill-of-materials-物料清单" tabindex="-1">BOM (Bill of Materials, 物料清单) <a class="header-anchor" href="#bom-bill-of-materials-物料清单" aria-label="Permalink to &quot;BOM (Bill of Materials, 物料清单)&quot;">​</a></h5><ul><li><p>定义：BOM 是一份包含层级关系的产品物料清单。它回答了产品所需的三个问题：</p><ul><li>用什么？ 物料编码，名称，规格。</li><li>用多少？ 单机用量、单位。</li><li>怎么组？ BOM 结构的层级关系代表了物料的从属关系和装配逻辑。</li></ul></li><li><p>分类： BOM 可以按照“生命周期阶段”和“数据结构形态”这两个维度来分类。通常是从“生命周期阶段”的维度来划分的。</p><ul><li><p>从“生命周期阶段”的维度可以划分为：EBOM、PBOM、MBOM等。</p></li><li><p>从“数据结构形态”的维度可以划分为：单层 BOM、多层 BOM、模块化 BOM、超级 BOM 等。</p></li></ul><blockquote><p>指的正是产品从<strong>概念设计</strong>到<strong>生产制造</strong>，再到销售服务，直至最后<strong>报废</strong>的全过程。</p></blockquote></li><li><p>示例：我们用一个“自行车”的例子来展示层级关系是如何构建出产品结构的。</p><table tabindex="0"><thead><tr><th style="text-align:left;">层级</th><th style="text-align:left;">物料名称</th><th style="text-align:left;">数量</th><th style="text-align:left;">关系含义</th></tr></thead><tbody><tr><td style="text-align:left;">0 层</td><td style="text-align:left;">自行车 (成品)</td><td style="text-align:left;">1</td><td style="text-align:left;">根节点：最终交付给客户的产品。</td></tr><tr><td style="text-align:left;">1 层</td><td style="text-align:left;">├── 车架组件</td><td style="text-align:left;">1</td><td style="text-align:left;">子装配：直接归属于成品的部件。</td></tr><tr><td style="text-align:left;">1 层</td><td style="text-align:left;">├── 车轮组件</td><td style="text-align:left;">2</td><td style="text-align:left;">子装配：需要 2 个。</td></tr><tr><td style="text-align:left;">2 层</td><td style="text-align:left;">    ├── 轮胎</td><td style="text-align:left;">1</td><td style="text-align:left;">零件：属于车轮的一部分。</td></tr><tr><td style="text-align:left;">2 层</td><td style="text-align:left;">    └── 轮毂</td><td style="text-align:left;">1</td><td style="text-align:left;">零件：属于车轮的一部分。</td></tr><tr><td style="text-align:left;">1 层</td><td style="text-align:left;">└── 传动系统</td><td style="text-align:left;">1</td><td style="text-align:left;">子装配：直接归属于成品的部件。</td></tr><tr><td style="text-align:left;">2 层</td><td style="text-align:left;">    ├── 链条</td><td style="text-align:left;">1</td><td style="text-align:left;">零件：属于传动系统。</td></tr><tr><td style="text-align:left;">2 层</td><td style="text-align:left;">    └── 脚踏</td><td style="text-align:left;">2</td><td style="text-align:left;">零件：属于传动系统。</td></tr></tbody></table><p>在这个结构中我们可以读出：</p><ol><li><strong>可视化结构</strong>： 我们可以清晰的看出，自行车是由车架、车轮、传动机构组成。</li><li><strong>数量关系</strong>：生产 1 辆自行车，需要 2 个车轮，因此需要 2 个轮胎和 2 个轮毂（系统会自动计算这种需求，这叫 MRP 运算）。</li><li><strong>管理粒度</strong>：企业决定将“车轮”作为一个中间层（子装配）来管理，意味着车轮可能是先组装好，再装到车架上；或者车轮是外购的成品。</li></ol></li></ul><h5 id="ebom-engineer-bom-设计-bom" tabindex="-1">EBOM （Engineer BOM, 设计 BOM） <a class="header-anchor" href="#ebom-engineer-bom-设计-bom" aria-label="Permalink to &quot;EBOM （Engineer BOM, 设计 BOM）&quot;">​</a></h5><ul><li>定义：EBOM 是<strong>产品设计阶段</strong>的 BOM，用于记录产品设计阶段的物料清单。</li><li>来源： 在现代 PLM/CAD 集成环境中，EBOM 不是人工手敲出来的，而是由系统自动生成的。 <ul><li><strong>生成机制</strong>：当结构工程师在 CAD 软件（如 NX, Creo, SolidWorks）中搭建装配体时，他实际上是在构建一个“父子关系树”。</li><li><strong>提取过程</strong>：PLM 系统通过接口读取 CAD 装配文件的内部结构，提取出“谁引用了谁”、“数量是多少”、“材质属性是什么”，然后自动映射生成 EBOM 树。</li></ul></li><li>历史：在 PLM 软件诞生之前（甚至在没有 CAD 的手工绘图时代），EBOM 依然存在，只是它的载体不同： <ul><li>纸质时代：工程师在图纸的右下角画一个“明细栏”。这张明细栏就是最原始的 EBOM。它列出了这个装配体用了哪些零件。</li><li>电子表格时代：有了 CAD 但没上 PLM 时，工程师画完图，会手动把明细栏里的内容敲进 Excel 里。这个 Excel 文件，就是 EBOM。</li><li>ERP 时代：很多公司只有 ERP，他们会要求研发把 Excel 里的 BOM 直接导入 ERP。这时候，ERP 里的那份数据，本质上也是 EBOM（虽然它被强行塞进了制造系统）。</li></ul></li></ul><h5 id="mbom-manufacture-bom-制造-bom" tabindex="-1">MBOM （Manufacture BOM, 制造 BOM） <a class="header-anchor" href="#mbom-manufacture-bom-制造-bom" aria-label="Permalink to &quot;MBOM （Manufacture BOM, 制造 BOM）&quot;">​</a></h5><ul><li><p>定义： MBOM 是面向<strong>车间生产制造</strong>的物料结构清单，是在 EBOM 或者 PBOM 基础上，工艺工程师根据工厂的工艺路线、赚不赔顺序，进行重新整理、拆分、调整后，给到ERP、MES、车间用的生产 BOM。它回答了以下问题：</p><ul><li>这个产品按照什么顺序装配？（先装底盘，在装发动机）。</li><li>除了设计零件，还需要哪些消耗品？（螺丝、胶水、螺母、螺栓）。</li><li>需要在哪个工位、用哪些工具来装配？</li></ul></li></ul><h5 id="pbom-process-bom-工艺-bom" tabindex="-1">PBOM （Process BOM, 工艺 BOM） <a class="header-anchor" href="#pbom-process-bom-工艺-bom" aria-label="Permalink to &quot;PBOM （Process BOM, 工艺 BOM）&quot;">​</a></h5><ul><li><p>定义：PBOM 是EBOM（设计）向 MBOM（制造）过渡的中间形态。如果说 EBOM 是“画出来的”，MBOM 是“车间用的”，那么 PBOM 就是“规划出来的”。它定义了产品如何被制造的工艺路线。</p></li><li><p>业务场景：</p><ul><li><p>在车间，工艺工程师需要根据 PBOM 来指导装配。</p></li><li><p>在 ERP 系统中，工艺工程师需要根据 PBOM 来指导生产。</p></li></ul></li></ul><h2 id="产品矩阵" tabindex="-1">产品矩阵 <a class="header-anchor" href="#产品矩阵" aria-label="Permalink to &quot;产品矩阵&quot;">​</a></h2><h3 id="plm-product-lifecycle-management-产品生命周期管理" tabindex="-1">PLM （Product Lifecycle Management，产品生命周期管理） <a class="header-anchor" href="#plm-product-lifecycle-management-产品生命周期管理" aria-label="Permalink to &quot;PLM （Product Lifecycle Management，产品生命周期管理）&quot;">​</a></h3><h3 id="ppm-project-portfolio-management-项目组合管理" tabindex="-1">PPM （Project Portfolio Management，项目组合管理） <a class="header-anchor" href="#ppm-project-portfolio-management-项目组合管理" aria-label="Permalink to &quot;PPM （Project Portfolio Management，项目组合管理）&quot;">​</a></h3><h3 id="pdm-product-data-management-产品数据管理" tabindex="-1">PDM （Product Data Management，产品数据管理） <a class="header-anchor" href="#pdm-product-data-management-产品数据管理" aria-label="Permalink to &quot;PDM （Product Data Management，产品数据管理）&quot;">​</a></h3><h3 id="mpm-manufacturing-process-management-制造过程管理" tabindex="-1">MPM （Manufacturing Process Management，制造过程管理） <a class="header-anchor" href="#mpm-manufacturing-process-management-制造过程管理" aria-label="Permalink to &quot;MPM （Manufacturing Process Management，制造过程管理）&quot;">​</a></h3><h3 id="mbse-model-based-systems-engineering-基于模型的系统工程" tabindex="-1">MBSE （Model-Based Systems Engineering，基于模型的系统工程） <a class="header-anchor" href="#mbse-model-based-systems-engineering-基于模型的系统工程" aria-label="Permalink to &quot;MBSE （Model-Based Systems Engineering，基于模型的系统工程）&quot;">​</a></h3><h4 id="rflp" tabindex="-1">RFLP <a class="header-anchor" href="#rflp" aria-label="Permalink to &quot;RFLP&quot;">​</a></h4><p>MBSE把设计过程分解为需求（Requirements）定义、功能（Function）分析、逻辑架构（Logical Architecture）设计、3D物理（Physical）设计，简称“RFLP”。RFLP贯穿于产品的整个生命周期，对于设计的每个过程构建相应的R模型、F模型、L模型和P模型，通过各个层次模型之间的关联关系，实现整个系统设计过程对需求的追溯和实现，以模型支撑整个系统的设计、分析、验证和确认等活动。</p><ul><li><p>需求层 （R 层）</p><ul><li>目标：捕获客户需求，进行设计需求的定义，将捕获的需求进行分类、分层的结构化组织和管理。</li><li>关键活动：需求分析、系统需求定义、需求分解与分配。</li><li>输出物：需求模型、需求追溯矩阵、需求规格说明书。</li></ul></li><li><p>功能层（F 层）</p><ul><li>目标：构建系统功能分析模型，进行系统功能的分析，构建系统的功能架构，对功能需求进行验证，并建立功能设计数据和需求之间的追溯关系。</li><li>关键活动：功能分解、功能流分析、接口定义。</li><li>输出物：功能架构模型、功能流程图、功能接口定义。</li></ul></li><li><p>逻辑层（L 层）</p><ul><li>目标：考虑各项性能需求，进行系统的架构设计，构建系统仿真模型，进行系统综合设计方案的论证，经过权衡分析，确定综合性能最优的系统设计方案，建立逻辑设计数据和功能设计数据或者需求间的追溯关系。</li><li>关键活动：逻辑架构设计、组件定义、逻辑接口定义、性能分析。</li><li>输出物：逻辑架构模型、组件规格、接口控制文档。</li></ul></li></ul><h3 id="erp-enterprise-resource-planning-企业资源计划" tabindex="-1">ERP （Enterprise Resource Planning，企业资源计划） <a class="header-anchor" href="#erp-enterprise-resource-planning-企业资源计划" aria-label="Permalink to &quot;ERP （Enterprise Resource Planning，企业资源计划）&quot;">​</a></h3><h3 id="mes-manufacturing-execution-system-制造执行系统" tabindex="-1">MES （Manufacturing Execution System，制造执行系统） <a class="header-anchor" href="#mes-manufacturing-execution-system-制造执行系统" aria-label="Permalink to &quot;MES （Manufacturing Execution System，制造执行系统）&quot;">​</a></h3>',23)]))}const g=e(n,[["render",r]]);export{c as __pageData,g as default};
